class LLMEval(ZhanlaComponent):
    component_type = ComponentType.LLM_EVAL

    def __init__(
        self,
        *,
        name: str,
        description: str,
        instructions: str | None = None,
        questions: list[str] | None = None,
        model: str,
        client: Any = None,
        runner: Runner | None = None,
        output_schema: Any = None,
        json_repair: bool = False,
        temperature: float | None = None,
        top_k: int | None = None,
        key: str,
    ) -> None:
        has_instructions = instructions is not None and instructions != ""
        has_questions = questions is not None and len(questions) > 0
        if has_instructions and has_questions:
            raise ValueError(
                f"LLMEval '{name}': provide exactly one of 'instructions' or 'questions', not both."
            )
        if not has_instructions and not has_questions:
            raise ValueError(
                f"LLMEval '{name}': must provide exactly one of 'instructions' or 'questions'."
            )
        if client is not None and runner is not None:
            raise ValueError("Specify client or runner, not both.")
        if client is not None:
            runner = Runner(client=client)
        self.name = name
        self.description = description
        self.instructions = instructions
        self.questions = questions
        self.model = model
        self.runner = runner
        self.output_schema = output_schema
        self.json_repair = json_repair
        self.temperature = temperature
        self.top_k = top_k
        _validate_key(key, name)
        self.key = key


class Conditional:
    """Routing primitive for orchestration steps."""

    def __init__(
        self,
        *,
        condition: Callable,
        if_true: str,
        if_false: str,
    ) -> None:
        self.condition = condition
        self.if_true = if_true
        self.if_false = if_false


class OrchestrationStep:
    """A single step in an orchestration DAG."""

    def __init__(
        self,
        *,
        component: ZhanlaComponent | Conditional,
        name: str,
        next: list[str] | None = None,
    ) -> None:
        self.component = component
        self.name = name
        self.next = next or []


class Orchestration(ZhanlaComponent):
    component_type = ComponentType.ORCHESTRATION

    def __init__(
        self,
        *,
        name: str,
        description: str,
        steps: list[OrchestrationStep],
        key: str,
    ) -> None:
        self.name = name
        self.description = description
        self.steps = steps
        _validate_key(key, name)
        self.key = key


# ---------------------------------------------------------------------------
# Eval composition
# ---------------------------------------------------------------------------

class Leaf:
    """Terminal scoring node in an EvalTree."""

    def __init__(self, *, eval: ZhanlaComponent) -> None:
        self.eval = eval


class Edge:
    """Weighted edge in an EvalTree."""

    def __init__(self, *, weight: float, node: Leaf | Branch) -> None:
        self.weight = weight
        self.node = node


class Branch:
    """Routing node in an EvalTree."""

    def __init__(
        self,
        *,
        eval: ZhanlaComponent,
        threshold: float,
        if_pass: list[Edge],
        if_fail: list[Edge],
    ) -> None:
        self.eval = eval
        self.threshold = threshold
        self.if_pass = if_pass
        self.if_fail = if_fail


class Checklist(ZhanlaComponent):
    component_type = ComponentType.CHECKLIST

    def __init__(
        self,
        *,
        name: str,
        description: str,
        evals: list[ZhanlaComponent],
        weights: list[float] | None = None,
        key: str,
    ) -> None:
        self.name = name
        self.description = description
        self.evals = evals
        self.weights = weights
        _validate_key(key, name)
        self.key = key


class EvalTree(ZhanlaComponent):
    component_type = ComponentType.EVAL_TREE

    def __init__(
        self,
        *,
        name: str,
        description: str,
        root: Branch,
        key: str,
    ) -> None:
        self.name = name
        self.description = description
        self.root = root
        _validate_key(key, name)
        self.key = key
